  | { kind: "rectangle"; width: number; height: number }
  | { kind: "triangle"; base: number; height: number };

// 类型收窄 —— TypeScript 通过 kind 自动推断具体类型
function area(shape: Shape): number {
  switch (shape.kind) {
    case "circle":
      // 此处 shape 已收窄为 { kind: "circle"; radius: number }
      return Math.PI * shape.radius ** 2;
    case "rectangle":
      return shape.width * shape.height;
    case "triangle":
      return (shape.base * shape.height) / 2;
  }
}
```

关键点：

- **`kind` 就是 discriminator**（可叫 `type` / `status` 等，只要每个 union 成员都有一个 literal 字段作为标签）。
- switch/case 或 if/else 判断 discriminator 后，TS 会自动收窄类型，访问该成员独有的属性不会报错。
- 新增一个变体（比如 `{ kind: "hexagon"; side: number }`），TS 会要求你补上对应的 case，否则编译报错 —— 这是 discriminated union 最大的价值：**增删变体时编译器替你兜底**。

